from __future__ import annotations

import argparse
import re
import sys
import zipfile
from pathlib import Path
from tempfile import TemporaryDirectory

from lxml import etree
from pptx import Presentation
from pptx.enum.shapes import MSO_SHAPE_TYPE


EMU_PER_INCH = 914400
XML_NS = {"a": "http://schemas.openxmlformats.org/drawingml/2006/main"}
CJK_RE = re.compile(r"[\u3400-\u9FFF\uF900-\uFAFF]")


def emu_to_inch(value: int) -> float:
    return value / EMU_PER_INCH


def iter_shapes(shape_collection):
    for shape in shape_collection:
        yield shape
        if shape.shape_type == MSO_SHAPE_TYPE.GROUP:
            yield from iter_shapes(shape.shapes)


def rail_audit(pptx_path: Path, content_max_y: float, footer_top: float, canvas_h: float):
    prs = Presentation(str(pptx_path))
    violations: list[str] = []
    for s_idx, slide in enumerate(prs.slides, 1):
        for shape in iter_shapes(slide.shapes):
            name = getattr(shape, "name", "") or ""
            top = emu_to_inch(shape.top)
            left = emu_to_inch(shape.left)
            right = emu_to_inch(shape.left + shape.width)
            bottom = emu_to_inch(shape.top + shape.height)
            if name.startswith("footer:"):
                if top < footer_top - 1e-3:
                    violations.append(f"slide {s_idx}: footer shape '{name}' top {top:.2f} < footer_top {footer_top:.2f}")
                if bottom > canvas_h + 1e-3:
                    violations.append(f"slide {s_idx}: footer shape '{name}' bottom {bottom:.2f} > canvas {canvas_h:.2f}")
                continue
            if left < -1e-3:
                violations.append(f"slide {s_idx}: shape '{name}' left {left:.2f} < 0")
            if right > 13.333 + 1e-3:
                violations.append(f"slide {s_idx}: shape '{name}' right {right:.2f} > slide width 13.33")
            if top < -1e-3:
                violations.append(f"slide {s_idx}: shape '{name}' top {top:.2f} < 0")
            if bottom > content_max_y + 1e-3:
                violations.append(f"slide {s_idx}: shape '{name}' bottom {bottom:.2f} > content_max_y {content_max_y:.2f}")
    return violations


def xml_audit(pptx_path: Path):
    warnings: list[str] = []
    with TemporaryDirectory() as tmp_dir:
        tmp_root = Path(tmp_dir)
        with zipfile.ZipFile(pptx_path, "r") as zin:
            zin.extractall(tmp_root)
        xml_files = list((tmp_root / "ppt").rglob("*.xml"))
        for xml_file in xml_files:
            text = xml_file.read_text(encoding="utf-8", errors="ignore")
            if "Calibri" in text:
                warnings.append(f"{xml_file.relative_to(tmp_root)} contains 'Calibri'")
            if "Microsoft JhengHei" in text:
                warnings.append(f"{xml_file.relative_to(tmp_root)} contains 'Microsoft JhengHei'")
        for slide_xml in sorted((tmp_root / "ppt" / "slides").glob("slide*.xml")):
            tree = etree.parse(str(slide_xml))
            for run in tree.xpath("//a:r", namespaces=XML_NS):
                text = "".join(run.xpath("./a:t/text()", namespaces=XML_NS))
                if not text:
                    continue
                rpr = run.find("./a:rPr", namespaces=XML_NS)
                if CJK_RE.search(text):
                    if rpr is not None and rpr.get("i") == "1":
                        warnings.append(f"{slide_xml.name}: CJK run is italic -> '{text[:24]}'")
                    if rpr is None or rpr.find("./a:ea", namespaces=XML_NS) is None:
                        warnings.append(f"{slide_xml.name}: CJK run missing <a:ea> -> '{text[:24]}'")
                else:
                    if rpr is None or rpr.find("./a:latin", namespaces=XML_NS) is None:
                        warnings.append(f"{slide_xml.name}: Latin run missing <a:latin> -> '{text[:24]}'")
    return warnings


